<?php
namespace App\Http\Controllers\Api\V1;
use App\Http\Controllers\Controller; use App\Http\Requests\ChangePasswordRequest; use App\Http\Requests\LoginRequest; use App\Http\Resources\UserResource; use App\Models\Footprint; use App\Models\User; use Illuminate\Http\JsonResponse; use Illuminate\Http\Request; use Illuminate\Support\Facades\Auth; use Illuminate\Support\Facades\Hash;
class AuthController extends Controller { public function login(LoginRequest $request): JsonResponse { $user=User::where('username',$request->username)->whereNull('disabled_at')->first(); if(!$user||!Hash::check($request->password,$user->password)){ return response()->json(['message'=>'Invalid credentials'],422); } Auth::login($user, true); $request->session()->regenerate(); return response()->json(['user'=>new UserResource($user)]); } public function logout(Request $request): JsonResponse { Auth::guard('web')->logout(); $request->session()->invalidate(); $request->session()->regenerateToken(); return response()->json(['ok'=>true]); } public function me(Request $request): UserResource { return new UserResource($request->user()); } public function changePassword(ChangePasswordRequest $request): JsonResponse { $request->user()->update(['password'=>$request->password]); Footprint::record('user.password_changed',$request->user()); return response()->json(['ok'=>true]); } }
